mapper.update:
UPDATE TB_BUSINESS
SET STATUS_CD = #{statusCd}
WHERE BIZ_NO = #{bizNo}

UPDATE TB_BUSINESS_AUTH
SET STATUS_CD = #{statusCd}
WHERE AUTH_ID = (
      SELECT AUTH_ID
        FROM TB_BUSINESS_AUTH
       WHERE BIZ_NO = #{bizNo}
       ORDER BY APPLY_DATE DESC
       FETCH FIRST 1 ROW ONLY
    )
